import fs from "node:fs/promises";
import https from "node:https";
import path from "node:path";
import vm from "node:vm";
import { fileURLToPath } from "node:url";

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
const appRoot = path.resolve(__dirname, "..");

const componentFiles = [
  "components/layout.babel.js",
  "components/hero.babel.js",
  "components/filters.babel.js",
  "components/buttons.babel.js",
  "components/access-panel.babel.js",
  "components/llm-prompts.babel.js",
  "components/content-hooks.babel.js",
  "components/app.babel.js",
];

function fetchText(url, redirectCount = 0) {
  return new Promise((resolve, reject) => {
    https.get(url, (response) => {
      if (response.statusCode && response.statusCode >= 300 && response.statusCode < 400 && response.headers.location) {
        if (redirectCount >= 5) {
          reject(new Error(`Too many redirects fetching ${url}`));
          response.resume();
          return;
        }

        const nextUrl = new URL(response.headers.location, url).toString();
        response.resume();
        resolve(fetchText(nextUrl, redirectCount + 1));
        return;
      }

      if (response.statusCode !== 200) {
        reject(new Error(`Failed to fetch ${url}: ${response.statusCode}`));
        response.resume();
        return;
      }

      let data = "";
      response.setEncoding("utf8");
      response.on("data", (chunk) => { data += chunk; });
      response.on("end", () => resolve(data));
    }).on("error", reject);
  });
}

async function loadBabel() {
  const source = await fetchText("https://unpkg.com/@babel/standalone/babel.min.js");
  const context = {
    console,
    setTimeout,
    clearTimeout,
  };
  context.window = context;
  context.self = context;
  context.globalThis = context;
  vm.createContext(context);
  vm.runInContext(source, context);

  if (!context.Babel) {
    throw new Error("Babel Standalone not loaded.");
  }

  return context.Babel;
}

async function build() {
  const Babel = await loadBabel();
  const outputParts = [
    "// Generated by scripts/build-components-bundle.mjs",
    "// Re-run this script after editing any *.babel.js component.",
  ];

  for (const relativePath of componentFiles) {
    const absolutePath = path.join(appRoot, relativePath);
    const source = await fs.readFile(absolutePath, "utf8");
    const result = Babel.transform(source, {
      presets: ["react"],
      sourceType: "script",
      comments: false,
      compact: false,
    });

    outputParts.push(`// ${relativePath}`);
    outputParts.push(result.code.trim());
  }

  const bundlePath = path.join(appRoot, "components.bundle.js");
  await fs.writeFile(bundlePath, outputParts.join("\n\n") + "\n", "utf8");
  console.log(`Bundle generated at ${bundlePath}`);
}

build().catch((error) => {
  console.error(error);
  process.exitCode = 1;
});
